    public void handleOHLCV(Client client, Object message)
    {
        //
        // spot
        //
        //    {
        //        "d": {
        //            "e": "spot@public.kline.v3.api",
        //            "k": {
        //                "t": 1678642261,
        //                "o": 20626.94,
        //                "c": 20599.69,
        //                "h": 20626.94,
        //                "l": 20597.06,
        //                "v": 27.678686,
        //                "a": 570332.77,
        //                "T": 1678642320,
        //                "i": "Min1"
        //            }
        //        },
        //        "c": "spot@public.kline.v3.api@BTCUSDT@Min1",
        //        "t": 1678642276459,
        //        "s": "BTCUSDT"
        //    }
        //
        // swap
        //
        //   {
        //       "channel": "push.kline",
        //       "data": {
        //         "a": 325653.3287,
        //         "c": 38839,
        //         "h": 38909.5,
        //         "interval": "Min1",
        //         "l": 38833,
        //         "o": 38901.5,
        //         "q": 83808,
        //         "rc": 38839,
        //         "rh": 38909.5,
        //         "rl": 38833,
        //         "ro": 38909.5,
        //         "symbol": "BTC_USDT",
        //         "t": 1651230660
        //       },
        //       "symbol": "BTC_USDT",
        //       "ts": 1651230713067
        //   }
        // protobuf
        //  {
        //    "channel":"spot@public.kline.v3.api.pb@BTCUSDT@Min1",
        //    "symbol":"BTCUSDT",
        //    "symbolId":"2fb942154ef44a4ab2ef98c8afb6a4a7",
        //    "createTime":"1754737941062",
        //    "publicSpotKline":{
        //       "interval":"Min1",
        //       "windowStart":"1754737920",
        //       "openingPrice":"117317.31",
        //       "closingPrice":"117325.26",
        //       "highestPrice":"117341",
        //       "lowestPrice":"117317.3",
        //       "volume":"3.12599854",
        //       "amount":"366804.43",
        //       "windowEnd":"1754737980"
        //    }
        // }
        //
        Object parsed = null;
        Object symbol = null;
        Object timeframe = null;
        if (Helpers.isTrue(Helpers.inOp(message, "publicSpotKline")))
        {
            symbol = this.symbol(this.safeString(message, "symbol"));
            Object data = this.safeDict(message, "publicSpotKline", new java.util.HashMap<String, Object>() {{}});
            Object timeframeId = this.safeString(data, "interval");
            timeframe = this.findTimeframe(timeframeId, Helpers.GetValue(this.options, "timeframes"));
            parsed = this.parseWsOHLCV(data, this.safeMarket(symbol));
        } else
        {
            Object d = this.safeValue2(message, "d", "data", new java.util.HashMap<String, Object>() {{}});
            Object rawOhlcv = this.safeValue(d, "k", d);
            Object timeframeId = this.safeString2(rawOhlcv, "i", "interval");
            Object timeframes = this.safeValue(this.options, "timeframes", new java.util.HashMap<String, Object>() {{}});
            timeframe = this.findTimeframe(timeframeId, timeframes);
            Object marketId = this.safeString2(message, "s", "symbol");
            Object market = this.safeMarket(marketId);
            symbol = Helpers.GetValue(market, "symbol");
            parsed = this.parseWsOHLCV(rawOhlcv, market);
        }
        Object messageHash = Helpers.add(Helpers.add(Helpers.add("candles:", symbol), ":"), timeframe);
        Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
        Object stored = this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        if (Helpers.isTrue(Helpers.isEqual(stored, null)))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            stored = new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue());
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, stored);
        }
        Helpers.callDynamically(stored, "append", new Object[]{parsed});
        client.resolve(stored, messageHash);
    }

    public Object parseWsOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        // spot
        //
        //    {
        //        "t": 1678642260,
        //        "o": 20626.94,
        //        "c": 20599.69,
        //        "h": 20626.94,
        //        "l": 20597.06,
        //        "v": 27.678686,
        //        "a": 570332.77,
        //        "T": 1678642320,
        //        "i": "Min1"
        //    }
        //
        // swap
        //    {
        //       "symbol": "BTC_USDT",
        //       "interval": "Min1",
        //       "t": 1680055080,
        //       "o": 27301.9,
        //       "c": 27301.8,
        //       "h": 27301.9,
        //       "l": 27301.8,
        //       "a": 8.19054,
        //       "q": 3,
        //       "ro": 27301.8,
        //       "rc": 27301.8,
        //       "rh": 27301.8,
        //       "rl": 27301.8
        //     }
        // protobuf
        //
        //       "interval":"Min1",
        //       "windowStart":"1754737920",
        //       "openingPrice":"117317.31",
        //       "closingPrice":"117325.26",
        //       "highestPrice":"117341",
        //       "lowestPrice":"117317.3",
        //       "volume":"3.12599854",
        //       "amount":"366804.43",
        //       "windowEnd":"1754737980"
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object volume = this.safeNumber2(ohlcv, "v", "volume");
        // MEXC swap websocket klines publish contracts volume in `q`,
        // while spot/protobuf uses `v`/`volume`.
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(market, null))) && Helpers.isTrue((!Helpers.isTrue(this.safeBool(market, "spot"))))) && Helpers.isTrue((Helpers.isEqual(volume, null)))))
        {
            volume = this.safeNumber2(ohlcv, "q", "v");
        }
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeTimestamp2(ohlcv, "t", "windowStart"), this.safeNumber2(ohlcv, "o", "openingPrice"), this.safeNumber2(ohlcv, "h", "highestPrice"), this.safeNumber2(ohlcv, "l", "lowestPrice"), this.safeNumber2(ohlcv, "c", "closingPrice"), volume));
    }

