    public void handleOrderBookSubscription(Client client, Object message)
    {
        // spot
        //     { id: 0, code: 0, msg: "spot@public.increase.depth.v3.api@BTCUSDT" }
        //
        Object msg = this.safeString(message, "msg");
        Object parts = Helpers.split(msg, "@");
        Object marketId = this.safeString(parts, 2);
        Object symbol = this.safeSymbol(marketId);
        Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}));
    }

    public Object getCacheIndex(Object orderbook, Object cache)
    {
        // return the first index of the cache that can be applied to the orderbook or -1 if not possible
        Object nonce = this.safeInteger(orderbook, "nonce");
        Object firstDelta = this.safeValue(cache, 0);
        Object firstDeltaNonce = this.safeIntegerN(firstDelta, new java.util.ArrayList<Object>(java.util.Arrays.asList("r", "version", "fromVersion")));
        if (Helpers.isTrue(Helpers.isLessThan(nonce, Helpers.subtract(firstDeltaNonce, 1))))
        {
            return Helpers.opNeg(1);
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(cache)); i++)
        {
            Object delta = Helpers.GetValue(cache, i);
            Object deltaNonce = this.safeIntegerN(delta, new java.util.ArrayList<Object>(java.util.Arrays.asList("r", "version", "fromVersion")));
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(deltaNonce, nonce)))
            {
                return i;
            }
        }
        return Helpers.getArrayLength(cache);
    }

    public void handleOrderBook(Client client, Object message)
    {
        //
        // spot
        //    {
        //        "c": "spot@public.increase.depth.v3.api@BTCUSDT",
        //        "d": {
        //            "asks": [{
        //                "p": "20290.89",
        //                "v": "0.000000"
        //            }],
        //            "e": "spot@public.increase.depth.v3.api",
        //            "r": "3407459756"
        //        },
        //        "s": "BTCUSDT",
        //        "t": 1661932660144
        //    }
        //
        //
        //
        // swap
        //  {
        //      "channel":"push.depth",
        //      "data":{
        //         "asks":[
        //            [
        //               39146.5,
        //               11264,
        //               1
        //            ]
        //         ],
        //         "bids":[
        //            [
        //               39144,
        //               35460,
        //               1
        //            ]
        //         ],
        //         "end":4895965272,
        //         "begin":4895965271
        //      },
        //      "symbol":"BTC_USDT",
        //      "ts":1651239652372
        //  }
        // protofbuf
        // {
        //      "channel":"spot@public.aggre.depth.v3.api.pb@100ms@BTCUSDT",
        //      "symbol":"BTCUSDT",
        //      "sendTime":"1754741322152",
        //      "publicAggreDepths":{
        //          "asks":[
        //              {
        //                  "price":"117145.49",
        //                  "quantity":"0"
        //              }
        //          ],
        //          "bids":[
        //              {
        //                  "price":"117053.41",
        //                  "quantity":"1.86837271"
        //              }
        //          ],
        //          "eventType":"spot@public.aggre.depth.v3.api.pb@100ms",
        //          "fromVersion":"43296363236",
        //          "toVersion":"43296363255"
        //      }
        // }
        //
        Object data = this.safeDictN(message, new java.util.ArrayList<Object>(java.util.Arrays.asList("d", "data", "publicAggreDepths")));
        Object marketId = this.safeString2(message, "s", "symbol");
        Object symbol = this.safeSymbol(marketId);
        Object messageHash = Helpers.add("orderbook:", symbol);
        Object subscription = this.safeValue(client.subscriptions, messageHash);
        Object limit = this.safeInteger(subscription, "limit");
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook());
        }
        Object storedOrderBook = Helpers.GetValue(this.orderbooks, symbol);
        Object nonce = this.safeInteger(storedOrderBook, "nonce");
        Object shouldReturn = false;
        if (Helpers.isTrue(Helpers.isEqual(nonce, null)))
        {
            Object cacheLength = Helpers.getArrayLength(((java.util.List<Object>)Helpers.GetValue(storedOrderBook, "cache")));
            Object snapshotDelay = this.handleOption("watchOrderBook", "snapshotDelay", 25);
            if (Helpers.isTrue(Helpers.isEqual(cacheLength, snapshotDelay)))
            {
                this.spawn(() -> { try { this.loadOrderBook(client, messageHash, symbol, limit, new java.util.HashMap<String, Object>() {{}}); } catch(Exception _e) { throw new RuntimeException(_e); } });
            }
            ((java.util.List<Object>)((java.util.List<Object>)Helpers.GetValue(storedOrderBook, "cache"))).add(data);
            return;
        }
        try
        {
            this.handleDelta(storedOrderBook, data);
            Object timestamp = this.safeIntegerN(message, new java.util.ArrayList<Object>(java.util.Arrays.asList("t", "ts", "sendTime")));
            Helpers.addElementToObject(storedOrderBook, "timestamp", timestamp);
            Helpers.addElementToObject(storedOrderBook, "datetime", this.iso8601(timestamp));
        } catch(Exception e)
        {
            ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
            client.reject(e, messageHash);
            // return;
            shouldReturn = true;
        }
        if (Helpers.isTrue(shouldReturn))
        {
            return;  // go requirement
        }
        client.resolve(storedOrderBook, messageHash);
    }

    public void handleBooksideDelta(Object bookside, Object bidasks)
    {
        //
        //    [{
        //        "p": "20290.89",
        //        "v": "0.000000"
        //    }]
        //
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(bidasks)); i++)
        {
            Object bidask = Helpers.GetValue(bidasks, i);
            if (Helpers.isTrue(Helpers.isArray(bidask)))
            {
                Helpers.callDynamically(bookside, "storeArray", new Object[]{bidask});
            } else
            {
                Object price = this.safeFloat2(bidask, "p", "price");
                Object amount = this.safeFloat2(bidask, "v", "quantity");
                Helpers.callDynamically(bookside, "store", new Object[]{price, amount});
            }
        }
    }

    public void handleDelta(Object orderbook, Object delta)
    {
        Object existingNonce = this.safeInteger(orderbook, "nonce");
        Object deltaNonce = this.safeIntegerN(delta, new java.util.ArrayList<Object>(java.util.Arrays.asList("r", "version", "fromVersion")));
        if (Helpers.isTrue(Helpers.isLessThan(deltaNonce, existingNonce)))
        {
            // even when doing < comparison, this happens: https://app.travis-ci.com/github/ccxt/ccxt/builds/269234741#L1809
            // so, we just skip old updates
            return;
        }
        Helpers.addElementToObject(orderbook, "nonce", deltaNonce);
        Object asks = this.safeList(delta, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object bids = this.safeList(delta, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object asksOrderSide = Helpers.GetValue(orderbook, "asks");
        Object bidsOrderSide = Helpers.GetValue(orderbook, "bids");
        this.handleBooksideDelta(asksOrderSide, asks);
        this.handleBooksideDelta(bidsOrderSide, bids);
    }

