    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        // public trade (protobuf)
        //    {
        //        "p": "20382.70",
        //        "v": "0.043800",
        //        "S": 1,
        //        "t": 1678593222456,
        //    }
        // private trade
        //    {
        //        "S": 1,
        //        "T": 1661938980268,
        //        "c": "",
        //        "i": "c079b0fcb80a46e8b128b281ce4e4f38",
        //        "m": 1,
        //        "p": "1.008",
        //        "st": 0,
        //        "t": "4079b1522a0b40e7919f609e1ea38d44",
        //        "v": "5"
        //    }
        //
        //   d: {
        //       p: '1.0005',
        //       v: '5.71',
        //       a: '5.712855',
        //       S: 1,
        //       T: 1714325698237,
        //       t: 'edafcd9fdc2f426e82443d114691f724',
        //       c: '',
        //       i: 'C02__413321238354677760043',
        //       m: 0,
        //       st: 0,
        //       n: '0.005712855',
        //       N: 'USDT'
        //   }
        // protobuf
        //
        //     {
        //        price: "3.6962",
        //        quantity: "1",
        //        amount: "3.6962",
        //        tradeType: 2,
        //        tradeId: "505979017439002624X1",
        //        orderId: "C02__505979017439002624115",
        //        feeAmount: "0.0003998377369698171",
        //        feeCurrency: "MX",
        //        time: 1736417034280
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger2(trade, "T", "time");
        Object tradeId = this.safeString2(trade, "t", "tradeId");
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            timestamp = this.safeInteger(trade, "t");
            tradeId = null;
        }
        Object priceString = this.safeString2(trade, "p", "price");
        Object amountString = this.safeString2(trade, "v", "quantity");
        Object rawSide = this.safeString2(trade, "S", "tradeType");
        Object side = ((Helpers.isTrue((Helpers.isEqual(rawSide, "1"))))) ? "buy" : "sell";
        Object isMaker = this.safeInteger(trade, "m");
        Object feeAmount = this.safeString2(trade, "n", "feeAmount");
        Object feeCurrencyId = this.safeString2(trade, "N", "feeCurrency");
        final Object finalTradeId = tradeId;
        final Object finalTimestamp = timestamp;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", finalTradeId );
            put( "order", MexcCore.this.safeString2(trade, "i", "orderId") );
            put( "timestamp", finalTimestamp );
            put( "datetime", MexcCore.this.iso8601(finalTimestamp) );
            put( "symbol", MexcCore.this.safeSymbol(null, market) );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", ((Helpers.isTrue((isMaker)))) ? "maker" : "taker" );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", MexcCore.this.safeString(trade, "amount") );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", feeAmount );
                put( "currency", MexcCore.this.safeCurrencyCode(feeCurrencyId) );
            }} );
        }}, market);
    }

